Ok I made further tests, actually it works with raw pointers, but not with shared_ptr. Here is a code snippet to reproduce the issue:

```c++
#include <pybind11/pybind11.h>
#include <pybind11/numpy.h>
#include <pybind11/stl.h>
#include <pybind11/numpy_array.h>
#include <iostream>

PYBIND11_DECLARE_HOLDER_TYPE(T, std::shared_ptr<T>);

namespace py = pybind11;

class Wrapper
{

public:

    Wrapper(double value) : m_value(value) {}

    double get_value() const { return m_value; }

private:

    double m_value;
};

void test_wrapper(std::shared_ptr<Wrapper> w1, std::shared_ptr<Wrapper> w2 = nullptr)
{
    std::cout << w1->get_value() << std::endl;
    if (w2)
    {
        std::cout << w2->get_value() << std::endl;
    }
}

PYBIND11_PLUGIN(dev_pybind)
{
	py::module m("dev_pybind", "pybind testing plugin");

    py::class_<Wrapper, std::shared_ptr<Wrapper>>(m, "Wrapper")
        .def(py::init<double>())
        .def("get_value", &Wrapper::get_value);

    m.def("test_wrapper", &test_wrapper, py::arg("w1"), py::arg("w2") = std::shared_ptr<Wrapper>(nullptr));

	return m.ptr();
}
```

In python:
